var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"WILBUR_NPC_NULL_NULL","text":{"KOREA":"도착했습니다, 여러분!","JPN":"着きました、みなさん！","ENG":"We're back, gentlemen!","TWN":"到了，各位！"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WILBUR_NPC_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"WILBUR_NPC_NULL_NULL","text":{"KOREA":"현실세계라고요! 이제 우리 모두 고생 끝, 행복 시작입니다!","JPN":"現実世界です！　もうこれで苦労は終わり、明るい未来が待っているのです！","ENG":"We're back in the Normalside! It's nothing but green pastures for us from here on out!","TWN":"是現實世界！我們終於苦盡甘來了。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WILBUR_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":null,"text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WILBUR_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"WILBUR_NPC_NULL_NULL","text":{"KOREA":"분위기가 이게 뭡니까, 다들? 갑자기 안 하던 다이브 멀미라도 시작했어요?","JPN":"この雰囲気はなんなんですか。急にダイブ酔いでも流行りだしたんですか？","ENG":"Come on, why the long face, everyone? Did you get Dive sickness or something?","TWN":"大家這是怎麼了？突然開始躍入眩暈了？"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WILBUR_NPC_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"PMC_NPC_TYPEA_NULL","text":{"KOREA":"이보세요. 고용주 양반.","JPN":"なあ、雇い主さんよ。","ENG":"Listen... Boss man.","TWN":"我說，雇主。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PMC_NPC_TYPEA_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WILBUR_NPC_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L10_1","type":"dialog","speaker":"PMC_NPC_TYPEA_NULL","text":{"KOREA":"역시 지금이라도 돌아갑시다. 대장이 못 탄 게 마음에 걸려.","JPN":"やはり戻ったほうがいいのでは。隊長を乗せられなかったのが気になる。","ENG":"Let's go back. It's not too late. I still feel guilty about leaving the Captain behind.","TWN":"還是回去吧。隊長沒有搭上船，我心裡有些擔心。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PMC_NPC_TYPEA_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WILBUR_NPC_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L11_1","type":"dialog","speaker":"WILBUR_NPC_NULL_NULL","text":{"KOREA":"하아...... 이 인간들 참 누가 가르쳤는지 줏대가 없구만......","JPN":"はあ……みなさん、何もわかってないのですね。","ENG":"*Sigh* Grow a spine already...","TWN":"哈啊……你們這群人，也不知道誰教得如此沒有骨氣……"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PMC_NPC_TYPEA_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WILBUR_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"WILBUR_NPC_NULL_NULL","text":{"KOREA":"언제 고장날지도 모르는 고물 배를 타고 생지옥으로 다시 기어들어가자고요?","JPN":"いつ壊れるかしらないポンコツ艦船に乗って、またあの生き地獄に戻るってことですか？","ENG":"You want to drag this old junk of a ship back to hell? After barely getting it off the ground?","TWN":"你現在是讓我再坐上隨時可能出故障的破船，再爬回地獄？"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PMC_NPC_TYPEA_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WILBUR_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"WILBUR_NPC_NULL_NULL","text":{"KOREA":"아니, 막말로 다시 간다고 해 보죠. 그래서 댁들이 뭘 할 수 있는데요?","JPN":"で、戻ったとしてあなたたちに何ができると思いますか？","ENG":"Fine, let's assume we're crazy enough to do that. What exactly will you do back down there?","TWN":"不是，就算回去了。那你們又能做什麼？"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PMC_NPC_TYPEA_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WILBUR_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"PMC_NPC_TYPEA_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PMC_NPC_TYPEA_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WILBUR_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"WILBUR_NPC_NULL_NULL","text":{"KOREA":"나눠야 할 몫만 늘어나는 겁니다. 나눠야 할 몫만.","JPN":"それに各々の取り分が減るだけですよ、わかってます？","ENG":"If anything, it'll only increase the number of folks to split the spoils with. Meaning less for you.","TWN":"每個人能分到的東西只會更少而已，懂不懂。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PMC_NPC_TYPEA_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WILBUR_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"WILBUR_NPC_NULL_NULL","text":{"KOREA":"잘 생각해 보세요. 저 이터니움을.","JPN":"よく考えてみてください。あのエタニウムを。","ENG":"Think about it. Look at all that Eternium.","TWN":"好好想想吧，那些永恆之金。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WILBUR_NPC_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"WILBUR_NPC_NULL_NULL","text":{"KOREA":"저걸 댁들끼리 나눠 가지면 용병 일에서 손 씻고 얼마든지 새로 시작할 수 있단 말입니다.","JPN":"あれをあなたたちだけで取り分ければ、傭兵の仕事なんかやめて新しい道を歩むことができるんですよ。","ENG":"If you split it among you, you could drop this mercenary work and get a brand new start.","TWN":"你們把那些永恆之金分了，從此金盆洗手，重新開始啊。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WILBUR_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"PMC_NPC_TYPEA_NULL","text":{"KOREA":"그건 그렇지만......","JPN":"そりゃあそうだが……","ENG":"Sure, but...","TWN":"雖然是如此……"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PMC_NPC_TYPEA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"WILBUR_NPC_NULL_NULL","text":{"KOREA":"자, 자. 더는 떠들 시간 없습니다.","JPN":"まあまあ、おしゃべりはこれくらいにしましょう。","ENG":"Come on, now. We can't afford any more chatter.","TWN":"好了，好了。沒時間在那跟你碎碎念了。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WILBUR_NPC_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"WILBUR_NPC_NULL_NULL","text":{"KOREA":"최대한 빨리 아티팩트와 이터니움을 안전한 곳으로 옮겨야 해요. 어떤 놈들이 냄새를 맡고 올지 모른단 말입니다.","JPN":"できるだけ早くアーティファクトとエタニウムを安全な場所に移さなければなりません。金のにおいを嗅ぎ付けた連中がいつ寄ってくるかわかりませんので。","ENG":"We've got to get the Artifacts and Eternium somewhere safe. There's no telling what sort of hyenas will sniff their way here.","TWN":"要快點把人造神器和永恆之金轉移到安全地帶。那些傢伙可能會聞著味道趕來呢。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WILBUR_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"PROFESSOR_NPC_NULL_NULL","text":{"KOREA":"오, 윌버 군. 마침 잘 왔습니다.","JPN":"おお、ウィルバー君。ちょうどよかった。","ENG":"Oh, Wilbur. Perfect timing.","TWN":"哦，韋爾伯。來得正好。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PROFESSOR_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"WILBUR_NPC_NULL_NULL","text":{"KOREA":"교...... 교수님?! 당신이 어떻게 여기......!","JPN":"きょ、教授！？　あなたがどうしてここに……！","ENG":"Prof... Professor?! How did you—","TWN":"教……教授？！您怎麼在這……！"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WILBUR_NPC_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"PROFESSOR_NPC_NULL_NULL","text":{"KOREA":"하하. 윌버 군 일행이 어디로 부상할지 예상하는 것쯤은 그리 어렵지 않아요.","JPN":"ハハハ。ウィルバー君たちがどこに浮上するか予想することくらい、簡単なことです。","ENG":"Hah hah. It wasn't so hard predicting where you'd be surfacing.","TWN":"哈哈。推測出你們一行人要躍出的位置並不是什麼難事。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PROFESSOR_NPC_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"PROFESSOR_NPC_NULL_NULL","text":{"KOREA":"애초에 이 함선도 우리 학회가 거래를 중간에서 조율해 줬으니 말입니다.","JPN":"そもそもこの艦船も、当学会が取引を調整したのですから。","ENG":"After all, our Society arranged for you to take this ship in the first place.","TWN":"當初這艘艦船也是我們學會在中間協調促成交易的。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PROFESSOR_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"WILBUR_NPC_NULL_NULL","text":{"KOREA":"......네?","JPN":"……えっ？","ENG":"What?","TWN":"……啊？"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WILBUR_NPC_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"PROFESSOR_NPC_NULL_NULL","text":{"KOREA":"그보다 이면세계에서 재미난 물건들을 많이도 가져왔군요.","JPN":"それより裏世界から面白そうなものをたくさん持ってきたのですね。","ENG":"In any case, you sure brought many interesting trinkets back from the Counterside.","TWN":"話說回來，聽說你們從異界帶回不少好東西呢。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PROFESSOR_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"WILBUR_NPC_NULL_NULL","text":{"KOREA":"큭......","JPN":"クッ……","ENG":"Ugh...","TWN":"呃……"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WILBUR_NPC_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"WILBUR_NPC_NULL_NULL","text":{"KOREA":"좋습니다. 이 기회를 빌어 분명히 말씀드려야겠군요.","JPN":"いいでしょう。この機会に、はっきりと言わせてもらいます。","ENG":"Very well. I'll take this opportunity to make myself clear, once and for all.","TWN":"好，剛好趁這個機會我也要把話說清楚。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WILBUR_NPC_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"WILBUR_NPC_NULL_NULL","text":{"KOREA":"여기 있는 모두, 전부!","JPN":"ここにあるものは、全部！","ENG":"All of this here...","TWN":"在這裡的所有東西，全部！"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WILBUR_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"WILBUR_NPC_NULL_NULL","text":{"KOREA":"온전히 제 업적입니다. 교수님이랑은 하등 상관없는 건이에요.","JPN":"噓偽りもなく僕の成果です。教授とは全く関係ありません。","ENG":"It's all my achievement alone. You've got nothing to do with this.","TWN":"這些都是我的功勞，跟教授您一點關係也沒有。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WILBUR_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"WILBUR_NPC_NULL_NULL","text":{"KOREA":"제가 탐사를 하겠다고 할 때 그렇게나 면박을 주셨죠?","JPN":"僕が探査をすると言った時、全然いい反応をしてくれなかったじゃないですか。","ENG":"Remember how you censured me when I said I'd go on this expedition?","TWN":"當初我說要勘探的時候，您就當面斥責我了吧？"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WILBUR_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"WILBUR_NPC_NULL_NULL","text":{"KOREA":"보세요! 누가 옳았는지 여기 이 아티팩트들이 증명해 주고 있지 않습니까!","JPN":"ほら、見てください！　誰が正しかったのか、このアーティファクトたちが証明してくれています！","ENG":"Now look! These Artifacts prove who was right all along!","TWN":"您看看！知道現在到底誰是正確的吧，這裡的人造神器就能證明了吧！"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WILBUR_NPC_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"WILBUR_NPC_NULL_NULL","text":{"KOREA":"어디 이 자리에서 똑같이 지껄여 보시죠!","JPN":"さあ、この場でも同じことが言えますか？","ENG":"Let's see if you can lecture me like before!","TWN":"看您現在還想狡辯什麼！"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WILBUR_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"PROFESSOR_NPC_NULL_NULL","text":{"KOREA":"윌버 군, 윌버 군......","JPN":"ああ、ウィルバー君……","ENG":"Oh, Wilbur, Wilbur...","TWN":"韋爾伯，韋爾伯……"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PROFESSOR_NPC_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"PROFESSOR_NPC_NULL_NULL","text":{"KOREA":"왜 그렇게 어리석습니까? 제 교육 방침에 문제가 있어서일까요?","JPN":"どうしてそんなに愚かなんでしょう。私の教育方針に問題があったせいでしょうか。","ENG":"Why are you so foolish? Have I taught you nothing?","TWN":"為什麼如此愚蠢呢？是因為我的教育方針有問題嗎？"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PROFESSOR_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"WILBUR_NPC_NULL_NULL","text":{"KOREA":"뭐...... 뭐요?","JPN":"な……なんですって？","ENG":"What... What are you talking about?","TWN":"什……什麼？"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WILBUR_NPC_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"PROFESSOR_NPC_NULL_NULL","text":{"KOREA":"......기관에서 냄새를 맡았군. 버넷 경의 후임들인가.","JPN":"……機関が嗅ぎ付いてきたな。バーネット卿の後任か。","ENG":"... The Institution got a whiff of this. Sir Burnett's successors, I suppose.","TWN":"……看來機關收到了消息。是伯內特爵士的繼任者嗎。"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PROFESSOR_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"PROFESSOR_NPC_NULL_NULL","text":{"KOREA":"윌버 군은 정말 경이로운 여정을 거치고 왔어요.","JPN":"ウィルバー君は実に驚異的な旅をしてきました。","ENG":"You were on a truly astonishing adventure, Wilbur.","TWN":"韋爾伯真是經歷了一次令人驚奇的旅程啊。"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PROFESSOR_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"PROFESSOR_NPC_NULL_NULL","text":{"KOREA":"그런데 정작 물욕에 눈이 어두워져 바로 옆에 있던 경이로운 산물들은 놓쳤더군요.","JPN":"ところが物欲に目がくらみ、すぐ目の前にあった驚異的な産物は逃してしまったようです。","ENG":"But you were so blinded by materialistic avarice that you missed the truly amazing treasures right next to you.","TWN":"但卻被物欲迷惑了眼睛，錯過了在身邊的驚奇產物啊。"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PROFESSOR_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"WILBUR_NPC_NULL_NULL","text":{"KOREA":"그게 무슨 소리야!","JPN":"どういうことだよ！","ENG":"What are you talking about?!","TWN":"您在說什麼！"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WILBUR_NPC_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"WILBUR_NPC_NULL_NULL","text":{"KOREA":"이것들을 봐! 전부 아티팩트야! 하나하나가 부르는 게 값인 보물들이라고!","JPN":"これを見ろ！　全部アーティファクトだ！　全部が言い値になる宝なんだぞ！","ENG":"Look at all this! They're all Artifacts! Each and every one of them will fetch any price I name!","TWN":"看看現在這些！全都是人造神器！每一個都是天價的寶物！"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WILBUR_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"PROFESSOR_NPC_NULL_NULL","text":{"KOREA":"부르는 게 값이라?","JPN":"言い値になると？","ENG":"Fetch any price you name?","TWN":"天價？"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PROFESSOR_NPC_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"PMC_NPC_TYPEA_NULL","text":{"KOREA":"뭐 해, 고용주 양반! 갑자기 밖에서 난리가 났다고!","JPN":"何やってるんだ、雇い主さんよ！　外は大騒ぎなんだぞ！","ENG":"Come on, boss! We've got a situation outside!","TWN":"你這是做什麼，雇主！外面突然亂成一團了！"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PMC_NPC_TYPEA_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WILBUR_NPC_NULL_NULL","face":"UNIT_HATE"}}},"sfx":"FX_CUTSCEN_DOOR_SF"},{"id":"L11_1","type":"dialog","speaker":"PMC_NPC_TYPEA_NULL","text":{"KOREA":"응? 당신들 뭐야!?","JPN":"え？　あんたたちは誰だ？","ENG":"Huh? Who the hell are you?!","TWN":"嗯？你們是誰！？"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PMC_NPC_TYPEA_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WILBUR_NPC_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L20_1","type":"dialog","speaker":"WILBUR_NPC_NULL_NULL","text":{"KOREA":"힉......! 히이이익......!","JPN":"ひっ……！　ひいいぃぃ……！","ENG":"Eeep! Eeek!","TWN":"噫……！噫……！"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WILBUR_NPC_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"PROFESSOR_NPC_NULL_NULL","text":{"KOREA":"그럴 때는 <color=#ffd34c>값을 매길 수 없다</color>고 해야지.","JPN":"そんなときは<color=#ffd34c>値段をつけることができない</color>と言わないと。","ENG":"The proper way to describe them is <color=#ffd34c>priceless</color>.","TWN":"那時候，應該說是<color=#ffd34c>無價之寶</color>啊。"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PROFESSOR_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"PROFESSOR_NPC_NULL_NULL","text":{"KOREA":"한때나마 자네를 가르쳤다는 것이 소름 끼칠 지경이야.","JPN":"一時的とはいえ、君が私の教え子だったということがゾッとするぐらいだ。","ENG":"It almost makes me sick to think you were once under my tutelage.","TWN":"雖然只教過你一陣子，但也足夠讓我起雞皮疙瘩了。"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PROFESSOR_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"PROFESSOR_NPC_NULL_NULL","text":{"KOREA":"물욕과 지적 욕구도 구분 못하는 식자가 원숭이보다 나을 게 뭐가 있나?","JPN":"物欲と知的欲求の区別すらできない識者は猿以下だと思わないかね。","ENG":"A scholar who cannot tell the difference between materialism and the true desire for knowledge is no better than an animal!","TWN":"物欲和求知欲都分不清的廢物，跟猴子有什麼區別？"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PROFESSOR_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"WILBUR_NPC_NULL_NULL","text":{"KOREA":"이...... 이...... 제, 젠장......!","JPN":"そ…そんな……ちくしょう……！","ENG":"You... Argh... Darn it!","TWN":"你……你……可、可惡……！"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WILBUR_NPC_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"PROFESSOR_NPC_NULL_NULL","text":{"KOREA":"이런. 바지를 적셨군. 아무래도 배변 훈련부터 다시 받아야겠어.","JPN":"おやおや、漏らしてしまったようだな。幼児レベルの教育訓練からやり直したほうがよさそうだ。","ENG":"Oh, my. You've wet yourself. Perhaps you should return to the basics, starting with potty training.","TWN":"哎呀。褲子都濕了。看來得從排便訓練開始重新教了。"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PROFESSOR_NPC_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"WILBUR_NPC_NULL_NULL","text":{"KOREA":"오, 오지 마! 오지 말라고!","JPN":"く、来るな！　来るなって！！","ENG":"S-stay back! Leave me alone!","TWN":"別、別過來！別過來！"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WILBUR_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"PROFESSOR_NPC_NULL_NULL","text":{"KOREA":"자네를 만나 보고 싶어하는 분이 계시네.","JPN":"君に会いたがっている方がいらっしゃる。","ENG":"There's someone who'd like to meet you.","TWN":"有人想見你。"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PROFESSOR_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"PROFESSOR_NPC_NULL_NULL","text":{"KOREA":"학회의 뜻이기도 하니, 사양하지 않길 바라지.","JPN":"学会の意思でもあるから、遠慮しないように。","ENG":"The Society also supports this meeting. I hope you'll humor us.","TWN":"這也是學會的意思，可別拒絕了喔。"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PROFESSOR_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};